order_id = #{orderId}, goods_id = #{goodsId}, quantity = #{quantity}, amount = #{amount}, price = #{price}, discount = #{discount}, sorting_price = #{sortingPrice}, old_sorting_weight = #{oldSortingWeight}, src_sorting_weight = #{srcSortingWeight}, src_sorting_quantity = #{srcSortingQuantity}, comment = #{comment}, create_time = #{createTime}, unit_id=#{unitId}, spu_no=#{spuNo}, sorting_status=#{sortingStatus}, print_status=#{printStatus}, last_modify_time = now()
