SELECT tb1.*, (CASE WHEN tb1.settlement_type = '1' THEN tb1.merchantName ELSE tb2.nickname END ) settlementName FROM ( SELECT DISTINCT t1.CODE, t1.dept_id, t5.dept_name deptName, t1.create_time createTime, t1.delivery_date deliveryDate, t2.spu_no spuNo, t4.NAME spuName, t2.price, t2.comment, t2.goods_id goodsId, t7.property_name goodsName, IFNULL( t2.sorting_price, 0 ) amount, IFNULL( t3.sorting_weight, 0 ) weight, IFNULL( t3.sorting_quantity, 0 ) quantity, t6.nickname merchantName, t6.customer_no, t6.settlement_type, t6.super_customer, case t1.status when '0' then '删除' when '1' then '待审核' when '2' then '待分拣' when '3' then '已分拣' when '4' then '已完成' when '5' then '已作废' end as status, case t1.pay_status when '0' then '未付款' when '1' then '已付款' end as payStatus, case t1.receipt_status when '0' then '未生成' when '1' then '已生成' end as receiptStatus FROM store_goods_order t1 JOIN store_goods_order_item t2 ON t1.order_id = t2.order_id AND t1.STATUS != '0' LEFT JOIN store_sorting_detail t3 ON t2.item_id = t3.order_item_id AND t3.STATUS = '1' AND t3.STATUS = '1' JOIN store_goods_quotation_goods t7 ON t7.goods_id = t2.goods_id JOIN store_goods_spu t4 ON t2.spu_no = t4.spu_no JOIN sys_dept t5 ON t5.dept_id = t1.dept_id JOIN store_member t6 ON t1.merchant_id = t6.id
and t1.dept_id = #{deptId}
AND t1.dept_id IN ( SELECT dept_id FROM sys_dept WHERE find_in_set( #{loginUserDeptId}, ancestors ) or dept_id=#{loginUserDeptId} )
and t1.delivery_date BETWEEN DATE_FORMAT(#{deliveryBeginDate},'%Y-%m-%d %H:%i:%s') AND DATE_FORMAT(#{deliveryEndDate},'%Y-%m-%d %H:%i:%s')
and t1.create_time BETWEEN DATE_FORMAT(#{createBeginDate},'%Y-%m-%d %H:%i:%s') AND DATE_FORMAT(#{createEndDate},'%Y-%m-%d %H:%i:%s')
and (t1.status in
#{statusValue}
or t1.old_status = 3
)
and ( t1.code like concat('%', #{orderKey}, '%') or t4.code like concat('%', #{orderKey}, '%') )
and ( t6.nickname like concat('%', #{deliveryKey}, '%') OR t6.phone like concat('%', #{deliveryKey}, '%') )
) tb1 LEFT JOIN store_member tb2 ON tb1.super_customer = tb2.customer_no
